{"content":"960:     /**
961:      * @return the full topology minus any global state
962:      */
963:     public synchronized ProcessorTopology buildTopology() {
964:         final Set<String> allNodes = new HashSet<>();
965:         for (final Set<String> value : nodeGroups().values()) {
966:             allNodes.addAll(value);
967:         }
968:         allNodes.removeAll(globalNodeGroups());
969: 
970:         initializeSubscription();
971:         initializeSubtopologyIdToStateStoreNamesMap();
972:         return build(allNodes);
973:     }
974: 
975:     /**
976:      * @param topicGroupId group of topics corresponding to a single subtopology
977:      * @return subset of the full topology
978:      */
979:     public synchronized ProcessorTopology buildSubtopology(final int topicGroupId) {
980:         final Set<String> nodeGroup = nodeGroups().get(topicGroupId);
981:         return build(nodeGroup);
982:     }
983: 
984:     /**
985:      * Builds the topology for any global state stores
986:      * @return ProcessorTopology of global state
987:      */
988:     public synchronized ProcessorTopology buildGlobalStateTopology() {
989:         Objects.requireNonNull(applicationId, "topology has not completed optimization");
990: 
991:         final Set<String> globalGroups = globalNodeGroups();
992:         if (globalGroups.isEmpty()) {
993:             return null;
994:         }
995:         return build(globalGroups);
996:     }
997: 
998:     private Set<String> globalNodeGroups() {
999:         final Set<String> globalGroups = new HashSet<>();
1000:         for (final Map.Entry<Integer, Set<String>> nodeGroup : nodeGroups().entrySet()) {
1001:             final Set<String> nodes = nodeGroup.getValue();
1002:             for (final String node : nodes) {
1003:                 if (isGlobalSource(node)) {
1004:                     globalGroups.addAll(nodes);
1005:                 }
1006:             }
1007:         }
1008:         return globalGroups;
1009:     }
1010: 
1011:     @SuppressWarnings("unchecked")
1012:     private ProcessorTopology build(final Set<String> nodeGroup) {
1013:         Objects.requireNonNull(applicationId, "topology has not completed optimization");
1014: 
1015:         final Map<String, ProcessorNode<?, ?, ?, ?>> processorMap = new LinkedHashMap<>();
1016:         final Map<String, SourceNode<?, ?>> topicSourceMap = new HashMap<>();
1017:         final Map<String, SinkNode<?, ?>> topicSinkMap = new HashMap<>();
1018:         final Map<String, StateStore> stateStoreMap = new LinkedHashMap<>();
1019:         final Set<String> repartitionTopics = new HashSet<>();
1020: 
1021:         // create processor nodes in a topological order ("nodeFactories" is already topologically sorted)
1022:         // also make sure the state store map values following the insertion ordering
1023:         for (final NodeFactory<?, ?, ?, ?> factory : nodeFactories.values()) {
1024:             if (nodeGroup == null || nodeGroup.contains(factory.name)) {
1025:                 final ProcessorNode<?, ?, ?, ?> node = factory.build();
1026:                 processorMap.put(node.name(), node);
1027: 
1028:                 if (factory instanceof ProcessorNodeFactory) {
1029:                     buildProcessorNode(processorMap,
1030:                                        stateStoreMap,
1031:                                        (ProcessorNodeFactory<?, ?, ?, ?>) factory,
1032:                                        (ProcessorNode<Object, Object, Object, Object>) node);
1033: 
1034:                 } else if (factory instanceof SourceNodeFactory) {
1035:                     buildSourceNode(topicSourceMap,
1036:                                     repartitionTopics,
1037:                                     (SourceNodeFactory<?, ?>) factory,
1038:                                     (SourceNode<?, ?>) node);
1039: 
1040:                 } else if (factory instanceof SinkNodeFactory) {
1041:                     buildSinkNode(processorMap,
1042:                                   topicSinkMap,
1043:                                   repartitionTopics,
1044:                                   (SinkNodeFactory<?, ?>) factory,
1045:                                   (SinkNode<?, ?>) node);
1046:                 } else {
1047:                     throw new TopologyException("Unknown definition class: " + factory.getClass().getName());
1048:                 }
1049:             }
1050:         }
