339:     /**
340:      * A user can provide either the config OPTIMIZE which means all optimizations rules will be
341:      * applied or they can provide a list of optimization rules.
342:      */
343:     private void optimizeTopology(final Properties props) {
344:         final Set<String> optimizationConfigs;
345:         if (props == null || !props.containsKey(StreamsConfig.TOPOLOGY_OPTIMIZATION_CONFIG)) {
346:             optimizationConfigs = Collections.emptySet();
347:         } else {
348:             optimizationConfigs = StreamsConfig.verifyTopologyOptimizationConfigs(
349:                 (String) props.get(StreamsConfig.TOPOLOGY_OPTIMIZATION_CONFIG));
350:         }
351:         if (optimizationConfigs.contains(StreamsConfig.REUSE_KTABLE_SOURCE_TOPICS)) {
352:             LOG.debug("Optimizing the Kafka Streams graph for ktable source nodes");
353:             reuseKTableSourceTopics();
354:         }
355:         if (optimizationConfigs.contains(StreamsConfig.MERGE_REPARTITION_TOPICS)) {
356:             LOG.debug("Optimizing the Kafka Streams graph for repartition nodes");
357:             mergeRepartitionTopics();
358:         }
359:         if (optimizationConfigs.contains(StreamsConfig.SINGLE_STORE_SELF_JOIN)) {
360:             LOG.debug("Optimizing the Kafka Streams graph for self-joins");
361:             rewriteSingleStoreSelfJoin(root, new IdentityHashMap<>());
362:         }
363:         LOG.debug("Optimizing the Kafka Streams graph for null-key records");
364:         rewriteRepartitionNodes();
365:     }
