367:     private void rewriteRepartitionNodes() {
368:         final Set<BaseRepartitionNode<?, ?>> nodes = new NodesWithRelaxedNullKeyJoinDownstream(root).find();
369:         for (final BaseRepartitionNode<?, ?> partitionNode : nodes) {
370:             if (partitionNode.processorParameters() != null) {
371:                 partitionNode.setProcessorParameters(new ProcessorParameters<>(
372:                     new KStreamFilter<>((k, v) -> k != null, false),
373:                     partitionNode.processorParameters().processorName()
374:                 ));
375:             }
376:         }
