45: 
46: public class ProcessorNode<KIn, VIn, KOut, VOut> {
47: 
48:     private static final Logger log = LoggerFactory.getLogger(ProcessorNode.class);
49:     private final List<ProcessorNode<KOut, VOut, ?, ?>> children;
50:     private final Map<String, ProcessorNode<KOut, VOut, ?, ?>> childByName;
51: 
52:     private final Processor<KIn, VIn, KOut, VOut> processor;
53:     private final FixedKeyProcessor<KIn, VIn, VOut> fixedKeyProcessor;
54:     private final String name;
55: 
56:     public final Set<String> stateStores;
57:     private ProcessingExceptionHandler processingExceptionHandler;
58: 
59:     private InternalProcessorContext<KOut, VOut> internalProcessorContext;
60:     private String threadId;
61: 
62:     private boolean closed = true;
63: 
64:     private Sensor droppedRecordsSensor;
65: 
66:     public ProcessorNode(final String name) {
67:         this(name, (Processor<KIn, VIn, KOut, VOut>) null, null);
68:     }
69: 
70:     public ProcessorNode(final String name,
71:                          final Processor<KIn, VIn, KOut, VOut> processor,
72:                          final Set<String> stateStores) {
73: 
74:         this.name = name;
75:         this.processor = processor;
76:         this.fixedKeyProcessor = null;
77:         this.children = new ArrayList<>();
78:         this.childByName = new HashMap<>();
79:         this.stateStores = stateStores;
80:     }
81: 
82:     public ProcessorNode(final String name,
83:                          final FixedKeyProcessor<KIn, VIn, VOut> processor,
84:                          final Set<String> stateStores) {
85: 
86:         this.name = name;
87:         this.processor = null;
88:         this.fixedKeyProcessor = processor;
89:         this.children = new ArrayList<>();
90:         this.childByName = new HashMap<>();
91:         this.stateStores = stateStores;
92:     }
93: 
94:     public final String name() {
95:         return name;
96:     }
97: 
98:     public List<ProcessorNode<KOut, VOut, ?, ?>> children() {
99:         return children;
100:     }
101: 
102:     ProcessorNode<KOut, VOut, ?, ?> child(final String childName) {
103:         return childByName.get(childName);
104:     }
105: 
106:     public void addChild(final ProcessorNode<KOut, VOut, ?, ?> child) {
107:         children.add(child);
108:         childByName.put(child.name, child);
109:     }
110: 
111:     public void init(final InternalProcessorContext<KOut, VOut> context) {
112:         if (!closed)
113:             throw new IllegalStateException("The processor is not closed");
114: 
115:         try {
116:             threadId = Thread.currentThread().getName();
117:             internalProcessorContext = context;
118:             droppedRecordsSensor = TaskMetrics.droppedRecordsSensor(threadId,
119:                 internalProcessorContext.taskId().toString(),
120:                 internalProcessorContext.metrics());
121: 
122:             if (processor != null) {
123:                 processor.init(context);
124:             }
125:             if (fixedKeyProcessor != null) {
126:                 @SuppressWarnings("unchecked") final FixedKeyProcessorContext<KIn, VOut> fixedKeyProcessorContext =
127:                     (FixedKeyProcessorContext<KIn, VOut>) context;
128:                 fixedKeyProcessor.init(fixedKeyProcessorContext);
129:             }
130:         } catch (final Exception e) {
131:             throw new StreamsException(String.format("failed to initialize processor %s", name), e);
132:         }
133: 
134:         // revived tasks could re-initialize the topology,
135:         // in which case we should reset the flag
136:         closed = false;
137:     }
138: 
139:     public void init(final InternalProcessorContext<KOut, VOut> context, final ProcessingExceptionHandler processingExceptionHandler) {
140:         init(context);
141:         this.processingExceptionHandler = processingExceptionHandler;
142:     }
143: 
144:     public void close() {
145:         throwIfClosed();
146: 
147:         try {
148:             if (processor != null) {
149:                 processor.close();
150:             }
151:             if (fixedKeyProcessor != null) {
152:                 fixedKeyProcessor.close();
153:             }
154:             internalProcessorContext.metrics().removeAllNodeLevelSensors(
155:                 threadId,
156:                 internalProcessorContext.taskId().toString(),
157:                 name
158:             );
159:         } catch (final Exception e) {
160:             throw new StreamsException(String.format("failed to close processor %s", name), e);
161:         }
162: 
163:         closed = true;
164:     }
165: 
166:     protected void throwIfClosed() {
167:         if (closed) {
168:             throw new IllegalStateException("The processor is already closed");
169:         }
170:     }
171: 
172: 
173:     public void process(final Record<KIn, VIn> record) {
174:         throwIfClosed();
175: 
176:         try {
177:             if (processor != null) {
178:                 processor.process(record);
179:             } else if (fixedKeyProcessor != null) {
180:                 fixedKeyProcessor.process(
181:                     InternalFixedKeyRecordFactory.create(record)
182:                 );
183:             } else {
184:                 throw new IllegalStateException(
185:                     "neither the processor nor the fixed key processor were set."
186:                 );
187:             }
188:         } catch (final ClassCastException e) {
189:             final String keyClass = record.key() == null ? "unknown because key is null" : record.key().getClass().getName();
190:             final String valueClass = record.value() == null ? "unknown because value is null" : record.value().getClass().getName();
191:             throw new StreamsException(String.format("ClassCastException invoking processor: %s. Do the Processor's "
192:                     + "input types match the deserialized types? Check the Serde setup and change the default Serdes in "
193:                     + "StreamConfig or provide correct Serdes via method parameters. Make sure the Processor can accept "
194:                     + "the deserialized input of type key: %s, and value: %s.%n"
195:                     + "Note that although incorrect Serdes are a common cause of error, the cast exception might have "
196:                     + "another cause (in user code, for example). For example, if a processor wires in a store, but casts "
197:                     + "the generics incorrectly, a class cast exception could be raised during processing, but the "
198:                     + "cause would not be wrong Serdes.",
199:                     this.name(),
200:                     keyClass,
201:                     valueClass),
